  phase_subrole = 'mobilize',
  coach_language = 'Use in Prepare / Access (mobilize) before higher-intent work. Secondary intent: hand intrinsic activation.',
  updated_at = now()
WHERE slug = 'finger-pulses' AND primary_phase_key = 'prepare_access';

