-- 8) Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary, what_it_is, why_it_matters,
  why_it_goes_here, programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name,
  e.card_summary,
  COALESCE(e.description, e.name),
  'Develops movement access and readiness for athletic training.',
  CASE e.phase_subrole
    WHEN 'raise' THEN 'Belongs in Raise — elevates temperature, blood flow, and general readiness without fatigue.'
    WHEN 'mobilize' THEN 'Belongs in Mobilize — opens joint ranges needed for later skill, speed, and strength work.'
    WHEN 'activate' THEN 'Belongs in Activate — wakes stabilizers and primes positions before integrated patterns.'
    WHEN 'integrate' THEN 'Belongs in Integrate — connects joints into whole-body movement chains.'
    WHEN 'potentiate_bridge' THEN 'Belongs in Potentiate Bridge — gently ramps neural intent toward Skill/Output without fatigue.'
    ELSE 'Place in Prepare / Access before higher-intent work.'
  END,
  'Use early in session; scale volume by age and attention. Stop before fatigue.',
  'Do not use as conditioning or max-effort work in the warm-up.',
  'Reduce reps, duration, or range for youth and beginners.'
FROM coaching.exercise e
WHERE e.slug IN ('9090-breathing-with-reach', 'crocodile-breathing', 'full-body-joint-cars-flow', 'neck-cars', 'cat-cow', 'quadruped-spinal-circles', 'quadruped-thread-the-needle', 'side-lying-open-book', 'inchworm-walkout', 'wrist-rockers-palms-down', 'wrist-rockers-palms-up', 'finger-pulses', 'scapular-push-up', 'quadruped-shoulder-circles', 'wall-slides-with-lift-off', 'band-external-rotation', 'arm-circles', 'bear-crawl-rock-back', 'down-dog-to-plank-wave', 'knee-to-wall-ankle-rockers', 'half-kneeling-ankle-dorsiflexion-pulse', 'ankle-cars', 'tibialis-raises', 'calf-raise-to-heel-drop', 'toe-yoga', 'short-foot-drill', 'foot-tripod-weight-shifts', 'low-pogos', 'jump-rope-easy-bounce', 'walking-knee-hug', 'walking-quad-pull', 'leg-swings-front-back', 'leg-swings-lateral', '9090-hip-switch', 'shin-box-switch', 'shin-box-get-up', 'hip-cars', 'adductor-rockback', 'frog-rockback', 'cossack-shift', 'deep-squat-pry', 'squat-to-stand-with-reach', 'lateral-lunge-shift', 'glute-bridge', 'glute-bridge-march', 'dead-bug-heel-tap', 'bird-dog', 'mini-band-lateral-walk', 'a-march', 'worlds-greatest-stretch')
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- 9) Representative cues
INSERT INTO coaching.exercise_cue (exercise_id, cue_type, body, sort_order)
SELECT e.id, v.cue_type, v.body, v.sort_order
FROM (VALUES
  ('deep-squat-pry', 'cue', 'Keep heels down and chest up in the bottom.', 0),
  ('deep-squat-pry', 'fault', 'Heels lifting off floor.', 1),
  ('glute-bridge', 'cue', 'Drive through heels; ribs down at top.', 0),
  ('glute-bridge', 'fault', 'Over-arching lower back.', 1),
  ('bear-crawl-rock-back', 'cue', 'Press palms; rock hips back with control.', 0),
  ('a-march', 'cue', 'Tall posture; quick sharp knee drive.', 0),
  ('a-march', 'fault', 'Leaning backward.', 1)
) AS v(slug, cue_type, body, sort_order)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE NOT EXISTS (
  SELECT 1 FROM coaching.exercise_cue c
  WHERE c.exercise_id = e.id AND c.cue_type = v.cue_type AND c.body = v.body
);
